import React, { useState } from 'react';
import "./CollapsedText.css";
import Accordion from 'react-bootstrap/Accordion';

function CollapsedText({name, text, buttonComponent, section}) {
  const [isOpen, setIsOpen] = useState(false);

  const toggleAccordion = () => {
    setIsOpen(!isOpen);
  };

  return (
    <Accordion>
      <Accordion.Item eventKey="0" id={section}>
        <Accordion.Header onClick={toggleAccordion}>
          <a href={`#${section}`}>{name}</a>
        </Accordion.Header>
        <Accordion.Body className={isOpen ? 'show' : 'hide'}>
          {text}
          {buttonComponent}
        </Accordion.Body>
      </Accordion.Item>
    </Accordion>
  );
}

export default CollapsedText;
